from crewai.flow.flow import Flow, listen, start
from pydantic import BaseModel

class ResearchState(BaseModel):
    topic: str = ""
    outline: str = ""
    article: str = ""

class ResearchFlow(Flow[ResearchState]):

    @start()
    def set_topic(self):
        self.state.topic = "quantum computing in 2024"
        return self.state.topic

    @listen(set_topic)
    def create_outline(self, topic: str):
        # In a real flow this would call a Crew or LLM
        self.state.outline = f"Outline for: {topic}"
        return self.state.outline

    @listen(create_outline)
    def write_article(self, outline: str):
        self.state.article = f"Article based on: {outline}"
        return self.state.article

flow = ResearchFlow()
result = flow.kickoff()
print(result)          # returns the final step's return value
print(flow.state)      # full state after all steps ran

from crewai.flow.flow import Flow, listen, router, start

class QualityState(BaseModel):
    draft: str = ""
    quality: str = ""   # "pass" or "fail"
    final: str = ""

class QualityFlow(Flow[QualityState]):

    @start()
    def write_draft(self):
        self.state.draft = "Initial draft text..."

    @router(write_draft)
    def check_quality(self):
        # Simple heuristic — in practice call an LLM reviewer
        word_count = len(self.state.draft.split())
        if word_count >= 50:
            self.state.quality = "pass"
            return "pass"
        else:
            self.state.quality = "fail"
            return "fail"

    @listen("pass")
    def publish(self):
        self.state.final = f"PUBLISHED: {self.state.draft}"
        return self.state.final

    @listen("fail")
    def revise(self):
        self.state.draft = self.state.draft + " Additional content added."
        return self.state.draft   # in a real flow, re-trigger the check

from crewai.flow.flow import Flow, listen, start, or_, and_

class ParallelState(BaseModel):
    section_a: str = ""
    section_b: str = ""
    merged: str = ""

class ParallelFlow(Flow[ParallelState]):

    @start()
    def kick_off(self):
        pass   # triggers both listeners below

    @listen(kick_off)
    def write_section_a(self):
        self.state.section_a = "Section A content"

    @listen(kick_off)
    def write_section_b(self):
        self.state.section_b = "Section B content"

    # Runs only when BOTH sections are complete
    @listen(and_(write_section_a, write_section_b))
    def merge_sections(self):
        self.state.merged = self.state.section_a + "\n" + self.state.section_b
        return self.state.merged

from pydantic import BaseModel
from crewai.flow.flow import Flow, listen, start

class DocumentState(BaseModel):
    title: str = ""
    sections: list[str] = []
    word_count: int = 0

class DocumentFlow(Flow[DocumentState]):

    @start()
    def initialise(self):
        # self.state is already populated from kickoff(inputs)
        print(f"Processing: {self.state.title}")

    @listen(initialise)
    def write_intro(self):
        intro = f"Introduction to {self.state.title}"
        self.state.sections.append(intro)
        self.state.word_count += len(intro.split())

    @listen(write_intro)
    def write_conclusion(self):
        conclusion = "In conclusion..."
        self.state.sections.append(conclusion)
        self.state.word_count += len(conclusion.split())
        return self.state.sections

# Pre-populate state at kickoff
flow = DocumentFlow()
result = flow.kickoff(inputs={"title": "AI Safety in 2024"})
print(flow.state.word_count)

class ParallelStartFlow(Flow):

    @start()
    def gather_market_data(self):
        # runs concurrently with gather_competitor_data
        self.state.market_data = "market snapshot"

    @start()
    def gather_competitor_data(self):
        # runs concurrently with gather_market_data
        self.state.competitor_data = "competitor snapshot"

    @listen(and_(gather_market_data, gather_competitor_data))
    def synthesise(self):
        # waits for BOTH start steps
        return f"{self.state.market_data} + {self.state.competitor_data}"

class RobustFlow(Flow[DocumentState]):

    @start()
    def fetch_data(self):
        try:
            # simulate external API call
            data = "fetched data"
            self.state.title = data
        except Exception as e:
            self.state.title = f"ERROR: {e}"

    @listen(fetch_data)
    def process(self):
        if self.state.title.startswith("ERROR"):
            # handle gracefully — don't crash the flow
            self.state.sections = ["Could not fetch data. Using cached version."]
        else:
            self.state.sections = [f"Processed: {self.state.title}"]

