import time

class TimedFlow(Flow[DocumentState]):

    def on_flow_start(self):
        self._start_time = time.time()
        print("Flow started")

    def on_flow_end(self):
        elapsed = time.time() - self._start_time
        print(f"Flow completed in {elapsed:.2f}s")

    @start()
    def step_one(self):
        self.state.title = "My Document"

    @listen(step_one)
    def step_two(self):
        self.state.sections.append("Section one")
